// ═══════════════════════════════════════════════
// Mapeo REAL de Factory IO Sorting Station
// Coils 0-6 escritos por Factory IO al PLC
// ═══════════════════════════════════════════════
var data = msg.payload;

var sensors = {
    atExit:        data[0] || false,   // Coil 0 = %M0 - Sensor At Exit
    startBtn:      data[1] || false,   // Coil 1 = %M1 - Start button (panel FIO)
    resetBtn:      data[2] || false,   // Coil 2 = %M2 - Reset button (panel FIO)
    stopBtn:       data[3] || false,   // Coil 3 = %M3 - Stop button (panel FIO)
    emergencyStop: data[4] || false,   // Coil 4 = %M4 - Emergency stop (seta)
    autoMode:      data[5] || false,   // Coil 5 = %M5 - Auto mode switch
    fioRunning:    data[6] || false    // Coil 6 = %M6 - Factory IO running
};

// Guardar en contexto de flujo
flow.set("sensors", sensors);

// Crear mensajes para cada LED del dashboard
var msgExit  = { payload: sensors.atExit };
var msgStart = { payload: sensors.startBtn };
var msgReset = { payload: sensors.resetBtn };
var msgStop  = { payload: sensors.stopBtn };
var msgEmg   = { payload: sensors.emergencyStop };
var msgAuto  = { payload: sensors.autoMode };
var msgFIO   = { payload: sensors.fioRunning };

return [msgExit, msgStart, msgReset, msgStop, msgEmg, msgAuto, msgFIO];

// ═══════════════════════════════════════════════
// Vision Sensor de Factory IO (Holding Register 0 = %MW0)
// Valores reales FIO: 0=nada, 1=azul, 4=verde, 7=metal
// ═══════════════════════════════════════════════
var value = msg.payload[0] || 0;

flow.set("visionSensor", value);

var colorMap = {
    0: { label: "⚫ Sin pieza",  color: "#555" },
    1: { label: "🔵 AZUL",      color: "#2196f3" },
    4: { label: "🟢 VERDE",     color: "#4caf50" },
    7: { label: "⚪ METÁLICO",  color: "#9e9e9e" }
};

var info = colorMap[value] || colorMap[0];

var msgText = { payload: info.label, color: info.color };
return msgText;

// ═══════════════════════════════════════════════
// Registros de proceso del PLC (%MW20-%MW25)
// Estos registros los escribe el programa Ladder
// ═══════════════════════════════════════════════
var data = msg.payload;

var process = {
    systemState:   data[0] || 0,
    totalCount:    data[1] || 0,
    blueCount:     data[2] || 0,
    greenCount:    data[3] || 0,
    metalCount:    data[4] || 0
};

// Guardar en contexto
flow.set("process", process);
global.set("processData", process);

// Estado del sistema con colores
var stateNames = ["⛔ PARADO", "✅ EN MARCHA", "⏸️ PAUSEDO", "🚨 EMERGENCY"];
var stateColors = ["#ff5722", "#4caf50", "#ff9800", "#f44336"];
var idx = Math.min(process.systemState, 3);

var msgState  = { payload: stateNames[idx], color: stateColors[idx] };
var msgTotal  = { payload: process.totalCount };
var msgBlue   = { payload: process.blueCount };
var msgGreen  = { payload: process.greenCount };
var msgMetal  = { payload: process.metalCount };

// Para gráfico de tendencias (Node-RED ui_chart) - SIN VELOCIDAD
var msgChartTotal = { topic: "Total Parts", payload: process.totalCount };

// Para alarmas y logging
var msgAlarm = {
    payload: process,
    state: stateNames[idx]
};

// output 6 era velocidad, ahora enviamos null o msg vacio
return [msgState, msgTotal, msgBlue, msgGreen, msgMetal, null, msgChartTotal, msgAlarm];

// Pulso de START: true → 500ms → false
var addr = 30;
var msgOn = { payload: { value: true, fc: 5, unitid: 1, address: addr, quantity: 1 } };
var msgOff = { payload: { value: false, fc: 5, unitid: 1, address: addr, quantity: 1 } };
node.send(msgOn);
setTimeout(function() { node.send(msgOff); }, 500);
return null;

// Pulso de EMERGENCY: true → 500ms → false
var addr = 34;
var msgOn = { payload: { value: true, fc: 5, unitid: 1, address: addr, quantity: 1 } };
var msgOff = { payload: { value: false, fc: 5, unitid: 1, address: addr, quantity: 1 } };
node.send(msgOn);
setTimeout(function() { node.send(msgOff); }, 500);
return null;

// Pulso de PAUSE: true → 500ms → false
var addr = 32;
var msgOn = { payload: { value: true, fc: 5, unitid: 1, address: addr, quantity: 1 } };
var msgOff = { payload: { value: false, fc: 5, unitid: 1, address: addr, quantity: 1 } };
node.send(msgOn);
setTimeout(function() { node.send(msgOff); }, 500);
return null;

// Pulso de RESET: true → 500ms → false
var addr = 33;
var msgOn = { payload: { value: true, fc: 5, unitid: 1, address: addr, quantity: 1 } };
var msgOff = { payload: { value: false, fc: 5, unitid: 1, address: addr, quantity: 1 } };
node.send(msgOn);
setTimeout(function() { node.send(msgOff); }, 500);
return null;

// Después de enviar un comando de tipo Coil, resetearlo a false
// para que funcione como pulso momentáneo
var addr = msg.payload.address;
var fc = msg.payload.fc;

if (fc === 5 && addr >= 30 && addr <= 34) {
    setTimeout(function() {
        node.send({
            payload: { value: false, fc: 5, unitid: 1, address: addr }
        });
    }, 500);
}
return null;

// Leer datos directamente del contexto global
var proc = global.get("processData");
if (!proc) { return null; }

var alarms = [];

// ── REPORTE CADA 50 PIEZAS ──
var lastReported = global.get("lastReportedTotal") || 0;
var currentTotal = proc.totalCount || 0;

if (currentTotal >= 50 && Math.floor(currentTotal / 50) > Math.floor(lastReported / 50)) {
    global.set("lastReportedTotal", currentTotal);
    alarms.push({
        tipo: "reporte",
        totalCount: currentTotal,
        blueCount: proc.blueCount || 0,
        greenCount: proc.greenCount || 0,
        metalCount: proc.metalCount || 0
    });
}

// ── DETECCIÓN DE EMERGENCY ──
var lastState = global.get("tg_lastSystemState");
if (lastState === undefined || lastState === null) { lastState = -1; }
var currentState = proc.systemState;

// El PLC puede mandar >= 3 para emergencia (el Dashboard usa Math.min(val, 3))
var esEmergencyAhora = (currentState >= 3);
var eraEmergencyAntes = (lastState >= 3);

// Detectar ENTRADA en emergencia
if (esEmergencyAhora && !eraEmergencyAntes) {
    alarms.push({
        tipo: "emergencia",
        variable: "System Status",
        valor: "EMERGENCY ACTIVA",
        icono: "🚨",
        accion: "Emergency stop pulsada! Revisar planta."
    });
}
// Detectar SALIDA de emergencia
else if (eraEmergencyAntes && !esEmergencyAhora) {
    alarms.push({
        tipo: "emergencia",
        variable: "System Status",
        valor: "EMERGENCY RESTABLECIDA",
        icono: "✅",
        accion: "El sistema ha salido del estado de emergencia."
    });
}

global.set("tg_lastSystemState", currentState);

if (alarms.length > 0) {
    msg.alarms = alarms;
    return msg;
}
return null;

// ════════════════════════════════════════════
// CONFIGURACIÓN: Poner aquí tu Chat ID de Telegram
var CHAT_ID = 8570340047;  // ← CAMBIAR POR TU CHAT ID
// ════════════════════════════════════════════

var alarms = msg.alarms;
var now = new Date();
var timestamp = now.toLocaleString('es-CO', {
    timeZone: 'America/Bogota',
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit'
});

var text = "";

for (var i = 0; i < alarms.length; i++) {
    var a = alarms[i];

    if (a.tipo === "reporte") {
        text += "📊 *REPORTE DE PRODUCCIÓN*\n";
        text += "━━━━━━━━━━━━━━━━━━━━\n\n";
        text += "📦 *Total de piezas:* `" + a.totalCount + "`\n\n";
        text += "🔵 Blue: `" + a.blueCount + "`\n";
        text += "🟢 Green: `" + a.greenCount + "`\n";
        text += "⚙️ Metallic: `" + a.metalCount + "`\n\n";
    } else if (a.tipo === "emergencia") {
        text += "🚨 *ALERTA CRÍTICA*\n";
        text += "━━━━━━━━━━━━━━━━━━━━\n\n";
        text += a.icono + " *" + a.variable + "*\n";
        text += "   📈 Valor: `" + a.valor + "`\n";
        text += "   💡 " + a.accion + "\n\n";
    }
}

text += "━━━━━━━━━━━━━━━━━━━━\n";
text += "🕐 " + timestamp + "\n";
text += "🏭 Sorting Station — Redes Com. Industrial";

msg.payload = {
    chatId: CHAT_ID,
    type: "message",
    content: text,
    options: { parse_mode: "Markdown" }
};
return msg;

// Registrar datos del proceso en CSV (Compatible con Excel Español)
var proc = msg.payload;
if (!proc || typeof proc !== 'object' || proc.systemState === undefined) {
    return null;
}
var sensors = flow.get('sensors') || {};
var vision = flow.get('visionSensor') || 0;
var now = new Date();

// Nombre del estado legible
var stateNames = ["Parado", "Running", "Pauseddo", "Emergency"];
var stateIdx = Math.min(proc.systemState, 3);

var line = [
    now.toISOString(),
    stateNames[stateIdx],
    proc.totalCount || 0,
    proc.blueCount || 0,
    proc.greenCount || 0,
    proc.metalCount || 0,
    vision,
    sensors.atExit ? 1 : 0,
    sensors.emergencyStop ? 1 : 0
].join(';'); // Usamos punto y coma para Excel

var dateStr = now.toISOString().split('T')[0];
var headerKey = 'csv_header_final_v1_' + dateStr;

// Si es la primera vez que escribimos hoy (o desde el deploy), inyectamos la cabecera
var finalPayload = "";
if (!global.get(headerKey)) {
    finalPayload = "timestamp;estado;total_piezas;azules;verdes;metalicas;vision_sensor;at_exit;emergency_stop\n";
    global.set(headerKey, true);
}

finalPayload += line;
msg.payload = finalPayload;
msg.filename = 'C:/Users/felex/Documents/Final Redes/reports/historial_' + dateStr + '.csv';

return msg;

var now = new Date();
var dateStr = now.toISOString().split('T')[0];
var mensaje = "<div style='text-align: center; color: white;'>";
mensaje += "✅ Informe del " + dateStr + " disponible.<br>";
mensaje += "Ruta: Final Redes/reports/historial_" + dateStr + ".csv<br>";
mensaje += "<a href='/report?fecha=" + dateStr + "' target='_blank' style='color: #4db8ff; text-decoration: none; font-weight: bold;'>Descargar: localhost:1880/report?fecha=" + dateStr + "</a>";
mensaje += "</div>";
msg.payload = mensaje;
return msg;

var fecha = msg.req.query.fecha;
if (!fecha) {
    var now = new Date();
    fecha = now.toISOString().split('T')[0];
}
msg.filename = "C:/Users/felex/Documents/Final Redes/reports/historial_" + fecha + ".csv";
return msg;

var data = msg.payload;
var colorMap = {
    "AZUL": "🔵 AZUL",
    "VERDE": "🟢 VERDE",
    "METALICO": "⚪ METÁLICO",
    "NINGUNO": "⚫ Sin detección"
};

var msgColor = { payload: colorMap[data.color_detectado] || data.color_detectado };

var c = data.contadores || {};
var msgCounters = {
    payload: "🔵 " + (c.AZUL||0) + "  🟢 " + (c.VERDE||0) + "  ⚪ " + (c.METALICO||0) + "  📦 " + (c.TOTAL||0)
};

var msgTime = {
    payload: data.timestamp ? new Date(data.timestamp).toLocaleTimeString() : "--"
};

flow.set("vision_data", data);
return [msgColor, msgCounters, msgTime];

var data = msg.payload;
var online = data.estado === "online";
msg.payload = online ? "🟢 Detector ONLINE" : "🔴 Detector OFFLINE";
return msg;

// Pulso de STOP NORMAL: true → 500ms → false
var addr = 31;
var msgOn = { payload: { value: true, fc: 5, unitid: 1, address: addr, quantity: 1 } };
var msgOff = { payload: { value: false, fc: 5, unitid: 1, address: addr, quantity: 1 } };
node.send(msgOn);
setTimeout(function() { node.send(msgOff); }, 500);
return null;

// Escribir bypass_color del QR al Holding Register 1 (%MW1)
// Valores: 0=Ninguno, 1=Azul, 4=Verde, 7=Metal
var data = msg.payload;
var bypassColor = data.bypass_color || 0;

node.status({fill: bypassColor > 0 ? 'yellow' : 'grey', shape: 'dot', text: 'Bypass: ' + (data.color_name || 'NINGUNO')});

msg.payload = { value: bypassColor, fc: 6, unitid: 1, address: 1 };
return msg;
